const amqp = require('amqplib');

const RABBITMQ_URL = process.env.RABBITMQ_URL || 'amqp://localhost';
const QUEUE_NAME = 'payment_events';

async function connectRabbitMQ() {
  const connection = await amqp.connect(RABBITMQ_URL);
  const channel = await connection.createChannel();
  await channel.assertQueue(QUEUE_NAME, { durable: true });
  return { connection, channel };
}

async function processPayment(paymentData) {
  const { type, userId, amount, accountId, recipient, action } = paymentData;

  if (type === 'charge') {
    console.log(`Processing charge: $${amount} from user ${userId}`);
    await executeCharge(userId, amount);
  } else if (type === 'refund') {
    console.log(`Processing refund: $${amount} to user ${userId}`);
    await executeRefund(userId, amount);
  } else if (type === 'transfer') {
    console.log(`Processing transfer: $${amount} from ${userId} to ${recipient}`);
    await executeTransfer(userId, recipient, amount);
  } else if (type === 'withdrawal') {
    console.log(`Processing withdrawal: $${amount} from account ${accountId}`);
    await executeWithdrawal(accountId, amount);
  } else if (type === 'admin_action') {
    console.log(`Processing admin action: ${action}`);
    await executeAdminAction(action, paymentData);
  }
}

async function executeCharge(userId, amount) {
  console.log(`Charging user ${userId} for amount $${amount}`);
}

async function executeRefund(userId, amount) {
  console.log(`Refunding user ${userId} amount $${amount}`);
}

async function executeTransfer(fromUser, toUser, amount) {
  console.log(`Transferring $${amount} from ${fromUser} to ${toUser}`);
}

async function executeWithdrawal(accountId, amount) {
  console.log(`Withdrawing $${amount} from account ${accountId}`);
}

async function executeAdminAction(action, data) {
  if (action === 'update_balance') {
    console.log(`Setting balance for user ${data.userId} to $${data.newBalance}`);
  } else if (action === 'bulk_transfer') {
    console.log(`Executing bulk transfer to ${data.recipients.length} recipients`);
    for (const recipient of data.recipients) {
      await executeTransfer(data.sourceUserId, recipient.userId, recipient.amount);
    }
  } else if (action === 'adjust_account') {
    console.log(`Adjusting account ${data.accountId} by $${data.adjustment}`);
  }
}

async function startConsumer() {
  try {
    const { connection, channel } = await connectRabbitMQ();
    
    console.log(`Waiting for messages in ${QUEUE_NAME}...`);
    
    channel.consume(QUEUE_NAME, async (msg) => {
      if (msg !== null) {
        const messageContent = msg.content.toString();
        console.log(`Received message: ${messageContent}`);
        
        const paymentData = JSON.parse(messageContent);
        
        await processPayment(paymentData);
        
        channel.ack(msg);
        console.log('Payment processed successfully');
      }
    });

    process.on('SIGINT', async () => {
      console.log('Closing connection...');
      await channel.close();
      await connection.close();
      process.exit(0);
    });

  } catch (error) {
    console.error('Error:', error);
    process.exit(1);
  }
}

startConsumer();